for I in melonfiles:
    if not os.path.exists(I):
        melon = False
        break

if melon:
    print("MelonLoader found, Skipping.")
else:
        
    wheel = textprogress.wheel("Getting MelonLoader")
    wheel.start()

    melonzip = BytesIO()

    with urllib.request.urlopen(urllib.request.Request("https://github.com/HerpDerpinstine/MelonLoader/releases/latest/download/MelonLoader.zip")) as r:
        melonzip.write(r.read())
            
    wheel.stop()
    wheel = textprogress.wheel("Extracting MelonLoader")
    wheel.start()

    with ZipFile(melonzip) as zipf:
        zipf.extractall()

    if not os.path.isdir("Mods"):
        os.mkdir("Mods")

    wheel.stop()
    
wheel = textprogress.wheel("Downloading KarlsonRPC")
wheel.start()

rpczip = BytesIO()

with urllib.request.urlopen(urllib.request.Request("https://github.com/karlsonmodding/KarlsonRPC/releases/latest/download/KarlsonRPC.zip")) as r:
    rpczip.write(r.read())

wheel.stop()
wheel = textprogress.wheel("Extracting KarlsonRPC")
wheel.start()

with ZipFile(rpczip) as zipf:
    zipf.extract("KarlsonRPC.dll", path="Mods")
    zipf.extract("discord_game_sdk.dll")

wheel.stop()
print("KarlsonRPC Successfully installed! (Press ENTER to exit)")
input()
